/**
 * Generates multiple tokens in batch for high-volume scenarios.
 * Uses crypto.randomBytes which is efficient even at high volumes.
 * @param count - Number of tokens to generate
 * @param prefix - The prefix for each token
 * @param byteLength - Number of random bytes per token (default: 32)
 * @returns An array of secure token strings
 */
export function generateTokenBatch(
  count: number,
  prefix: string = "tok",
  byteLength: number = 32
): string[] {
  if (count < 1) {
    throw new Error("Count must be at least 1.");
  }
  if (byteLength < 16) {
    throw new Error("Token byte length must be at least 16 for adequate security.");
  }

  // Allocate one large buffer for efficiency in high-volume scenarios
  const totalBytes = count * byteLength;
  const buffer = randomBytes(totalBytes);
  const tokens: string[] = new Array(count);

  for (let i = 0; i < count; i++) {
    const offset = i * byteLength;
    const randomPart = buffer.subarray(offset, offset + byteLength).toString("hex");
    tokens[i] = `${prefix}_${randomPart}`;
  }

  return tokens;
}

